export function calculateCartTotal(subtotal: number, discount: number, taxRate: number) {
  const total = subtotal * (1 + taxRate)
  const discounted = total - discount
  return Number(discounted.toFixed(2))
}

export function explainCheckout(cart: Cart) {
  return `Checkout cart with subtotal ${cart.subtotal}, discount ${cart.discount}, tax ${cart.taxRate}`
}

export function applyDiscount(subtotal: number, discount: number) {
  return Math.max(0, subtotal - discount)
}

export function isCheckoutDiscountValid(discount: number, subtotal: number) {
  return discount >= 0 && discount <= subtotal
}

export function applyTax(amount: number, taxRate: number) {
  return amount * (1 + taxRate)
}

export function taxLineItem(amount: number, taxRate: number) {
  return { label: 'Tax', amount: amount * taxRate }
}

import { calculateCartTotal } from './cart'

test('checkout discount applies before tax', () => {
  expect(calculateCartTotal(100, 20, 0.1)).toBe(88)
})

test('cart keeps tax consistent', () => {
  expect(calculateCartTotal(50, 0, 0.1)).toBe(55)
})

